import sys
from itertools import product

def main():
    N = int(sys.stdin.readline())
    R = sys.stdin.readline().strip()
    C = sys.stdin.readline().strip()

    # Initialize grid with empty cells
    grid = [['.' for _ in range(N)] for _ in range(N)]

    # Place the leftmost character in each row
    for i in range(N):
        for j in range(N):
            if grid[i][j] == '.':
                grid[i][j] = R[i]
                break

    # Place the topmost character in each column
    for j in range(N):
        for i in range(N):
            if grid[i][j] == '.':
                grid[i][j] = C[j]
                break

    # Check if the grid is valid
    def is_valid(grid):
        for row in grid:
            chars = [c for c in row if c != '.']
            if sorted(chars) != ['A', 'B', 'C']:
                return False
        for j in range(N):
            chars = [grid[i][j] for i in range(N) if grid[i][j] != '.']
            if sorted(chars) != ['A', 'B', 'C']:
                return False
        return True

    # Backtracking to fill the rest of the grid
    def backtrack(grid, row, col):
        if row == N:
            return is_valid(grid)
        if col == N:
            return backtrack(grid, row + 1, 0)
        if grid[row][col] != '.':
            return backtrack(grid, row, col + 1)

        for c in ['A', 'B', 'C']:
            if c in grid[row] or c in [grid[row][col] for row in range(N)]:
                continue
            grid[row][col] = c
            if backtrack(grid, row, col + 1):
                return True
            grid[row][col] = '.'
        return False

    if backtrack(grid, 0, 0):
        print("Yes")
        for row in grid:
            print(''.join(row))
    else:
        print("No")

if __name__ == "__main__":
    main()
